+    ASSERT_EQ(asx_local_scope_spawn_captured(&scope, poll_immediate_ok, 16u, NULL, &handle, &state),
+              ASX_OK);
+    ASSERT_TRUE(state != NULL);
+    ASSERT_EQ(asx_local_scope_spawned_count(&scope), 1u);
+    teardown();
+}
