+    RUN_TEST(local_scope_run_and_join);
+    RUN_TEST(local_scope_spawn_captured_success);
+    RUN_TEST(local_handle_abort_null_fails);
+    RUN_TEST(local_handle_try_join_null_fails);
+    TEST_REPORT();
+    return test_failures;
+}

